class MinHeap {
  private data: number[] = [];

  push(val: number) {
    this.data.push(val);
    this.bubbleUp(this.data.length - 1);
  }

  pop() {
    const top = this.data[0];
    const last = this.data.pop()!;
    if (this.data.length > 0) {
      this.data[0] = last;
      this.sinkDown(0);
    }
    return top;
  }

  size() {
    return this.data.length;
  }

  peek() {
    return this.data[0];
  }

  toArray() {
    return [...this.data];
  }

  private bubbleUp(idx: number) {
    while (idx > 0) {
      const parentIdx = (idx - 1) >> 1;
      if (this.data[parentIdx] <= this.data[idx]) break;
      [this.data[parentIdx], this.data[idx]] = [this.data[idx], this.data[parentIdx]];
      idx = parentIdx;
    }
  }

  private sinkDown(idx: number) {
    const n = this.data.length;
    while (true) {
      let smallest = idx;
      const left = 2 * idx + 1;
      const right = 2 * idx + 2;
      if (left < n && this.data[left] < this.data[smallest]) smallest = left;
      if (right < n && this.data[right] < this.data[smallest]) smallest = right;
      if (smallest === idx) break;
      [this.data[smallest], this.data[idx]] = [this.data[idx], this.data[smallest]];
      idx = smallest;
    }
  }
}

export function kLargestElementsInStream(stream: number[], k: number): number[][] {
  const result: number[][] = [];
  const heap = new MinHeap();

  for (const num of stream) {
    if (heap.size() < k) {
      heap.push(num);
    } else if (k > 0 && num > heap.peek()!) {
      heap.pop();
      heap.push(num);
    }
    result.push(heap.toArray().sort((a, b) => b - a));
  }

  return result;
}

