export function aStarGridShortestPath(grid: number[][], start: readonly [number, number], end: readonly [number, number]): number | null {
  const rows = grid.length;
  if (rows === 0) return null;
  const cols = grid[0].length;
  const [sx, sy] = start;
  const [ex, ey] = end;

  if (sx < 0 || sx >= rows || sy < 0 || sy >= cols || ex < 0 || ex >= rows || ey < 0 || ey >= cols) return null;
  if (grid[sx][sy] === 1 || grid[ex][ey] === 1) return null;
  if (sx === ex && sy === ey) return 0;

  const visited = Array.from({ length: rows }, () => new Array(cols).fill(false));
  const heap: { x: number; y: number; g: number; f: number }[] = [];

  const push = (node: { x: number; y: number; g: number; f: number }) => {
    heap.push(node);
    let i = heap.length - 1;
    while (i > 0) {
      const parent = (i - 1) >> 1;
      if (heap[i].f < heap[parent].f) {
        [heap[i], heap[parent]] = [heap[parent], heap[i]];
        i = parent;
      } else break;
    }
  };

  const pop = () => {
    const top = heap[0];
    const last = heap.pop()!;
    if (heap.length > 0) {
      heap[0] = last;
      let i = 0;
      const n = heap.length;
      while (true) {
        let smallest = i;
        const l = 2 * i + 1, r = 2 * i + 2;
        if (l < n && heap[l].f < heap[smallest].f) smallest = l;
        if (r < n && heap[r].f < heap[smallest].f) smallest = r;
        if (smallest !== i) {
          [heap[i], heap[smallest]] = [heap[smallest], heap[i]];
          i = smallest;
        } else break;
      }
    }
    return top;
  };

  push({ x: sx, y: sy, g: 0, f: Math.abs(sx - ex) + Math.abs(sy - ey) });

  const dirs = [[0, 1], [0, -1], [1, 0], [-1, 0]];

  while (heap.length > 0) {
    const current = pop();
    if (visited[current.x][current.y]) continue;
    visited[current.x][current.y] = true;

    if (current.x === ex && current.y === ey) return current.g;

    for (const [dx, dy] of dirs) {
      const nx = current.x + dx;
      const ny = current.y + dy;
      if (nx >= 0 && nx < rows && ny >= 0 && ny < cols && grid[nx][ny] === 0 && !visited[nx][ny]) {
        const ng = current.g + 1;
        const nh = Math.abs(nx - ex) + Math.abs(ny - ey);
        push({ x: nx, y: ny, g: ng, f: ng + nh });
      }
    }
  }

  return null;
}

