Heap structure:
```typescript
class MinHeap<T> {
  data: T[] = [];
  push(item: T) { this.data.push(item); this._bubbleUp(this.data.length - 1); }
  pop(): T | undefined {
    const top = this.data[0];
    const bottom = this.data.pop();
    if (this.data.length > 0 && bottom !== undefined) {
      this.data[0] = bottom;
      this._sinkDown(0);
    }
    return top;
  }
  get size() { return this.data.length; }
  private _compare(a: T, b: T): number { return a.f - b.f; }
  private _bubbleUp(i: number) {
    while (i > 0) {
      const parent = (i - 1) >> 1;
      if (this._compare(this.data[i], this.data[parent]) < 0) {
        [this.data[i], this.data[parent]] = [this.data[parent], this.data[i]];
        i = parent;
      } else break;
    }
  }
  private _sinkDown(i: number) {
    const n = this.data.length;
    while (true) {
      let smallest = i;
      const l = 2 * i + 1, r = 2 * i + 2;
      if (l < n && this._compare(this.data[l], this.data[smallest]) < 0) smallest = l;
