export function quicksort(arr: number[]): number[] {
  if (arr.length <= 1) {
    return [...arr];
  }

  const pivot = arr[Math.floor(arr.length / 2)];
  const left: number[] = [];
  const middle: number[] = [];
  const right: number[] = [];

  for (const num of arr) {
    if (num < pivot) {
      left.push(num);
    } else if (num > pivot) {
      right.push(num);
    } else {
      middle.push(num);
    }
  }

  return [...quicksort(left), ...middle, ...quicksort(right)];
}

