    for (let i = 0; i < nums.length; i++) {
        const complement = target - nums[i];
        const prevIndex = map.get(complement);
        if (prevIndex !== undefined) {
            return [prevIndex, i];
        }
        map.set(nums[i], i);
    }
    return null;
}
