export function unionFindConnectedComponentsOnline(n: number, operations: readonly (readonly [number, number])[]): number[] {
    const parent = new Array(n);
    const rank = new Array(n).fill(0);
    for (let i = 0; i < n; i++) parent[i] = i;

    let components = n;
    const res: number[] = [];

    function find(i: number): number {
        let root = i;
        while (parent[root] !== root) root = parent[root];
        while (i !== root) {
            const next = parent[i];
            parent[i] = root;
            i = next;
        }
        return root;
    }

    for (const [u, v] of operations) {
        let rootU = find(u);
        let rootV = find(v);
        if (rootU !== rootV) {
            if (rank[rootU] < rank[rootV]) {
                parent[rootU] = rootV;
            } else if (rank[rootU] > rank[rootV]) {
                parent[rootV] = rootU;
            } else {
                parent[rootV] = rootU;
                rank[rootU]++;
            }
            components--;
        }
        res.push(components);
    }

    return res;
}

