export function fftBigintMultiplyDigitArrays(a: number[], b: number[]): number[] {
    if (a.length === 0 || b.length === 0) return [];
    if (a.every(v => v === 0) || b.every(v => v === 0)) return [0];

    const aRev = a.slice().reverse();
    const bRev = b.slice().reverse();

    let n = 1;
    while (n < aRev.length + bRev.length) n <<= 1;

    const fa = new Array(2 * n).fill(0);
    const fb = new Array(2 * n).fill(0);

    for (let i = 0; i < aRev.length; i++) fa[i << 1] = aRev[i];
    for (let i = 0; i < bRev.length; i++) fb[i << 1] = bRev[i];

    function fft(arr: number[], invert: boolean) {
        const len = arr.length >> 1;
        let j = 0;
        for (let i = 1; i < len; i++) {
            const bit = len >> 1;
            for (; j & bit; bit >>= 1) j ^= bit;
            j ^= bit;
            if (i < j) {
                const tr = arr[i << 1]; const ti = arr[(i << 1) + 1];
                arr[i << 1] = arr[j << 1]; arr[(i << 1) + 1] = arr[(j << 1) + 1];
                arr[j << 1] = tr; arr[(j << 1) + 1] = ti;
            }
        }
        for (let l = 2; l <= len; l <<= 1) {
            const ang = (2 * Math.PI / l) * (invert ? -1 : 1);
            const wlen_r = Math.cos(ang);
            const wlen_i = Math.sin(ang);
            for (let i = 0; i < len; i += l) {
                let w_r = 1;
                let w_i = 0;
                for (let k = 0; k < l >> 1; k++) {
