                    const i2 = (i + k + (l >> 1)) << 1;
                    const u_r = arr[i1];
                    const u_i = arr[i1 + 1];
                    const v_r = arr[i2] * w_r - arr[i2 + 1] * w_i;
                    const v_i = arr[i2] * w_i + arr[i2 + 1] * w_r;
                    arr[i1] = u_r + v_r;
                    arr[i1 + 1] = u_i + v_i;
                    arr[i2] = u_r - v_r;
                    arr[i2 + 1] = u_i - v_i;
                    const next_w_r = w_r * wlen_r - w_i * wlen_i;
