export function mergeSortLinkedList(head: {value: number; next: any} | null): {value: number; next: any} | null {
	if (!head || !head.next) return head;

	let slow = head;
	let fast = head.next;
	while (fast && fast.next) {
		slow = slow.next;
		fast = fast.next.next;
	}

	const secondHalf = slow.next;
	slow.next = null;

	const left = mergeSortLinkedList(head);
	const right = mergeSortLinkedList(secondHalf);

	const dummy: {value: number; next: any} = { value: 0, next: null };
	let curr = dummy;

	while (left && right) {
		if (left.value <= right.value) {
			curr.next = left;
			left = left.next;
		} else {
			curr.next = right;
			right = right.next;
		}
		curr = curr.next;
	}

	curr.next = left || right;
	return dummy.next;
}

