  const MAX_KEYS = 2 * t - 1;
  const MIN_KEYS = Math.ceil(2 * MAX_KEYS / 3);

  type Node = {
    keys: number[];
    children: Node[];
    isLeaf: boolean;
  };

  let root: Node = { keys: [], children: [], isLeaf: true };

  function search(key: number, node: Node = root): boolean {
    let i = 0;
    while (i < node.keys.length && key > node.keys[i]) i++;
    if (i < node.keys.length && key === node.keys[i]) return true;
    if (node.isLeaf) return false;
    return search(key, node.children[i]);
  }

