    const child = parent.children[i];
    if (i > 0) {
      const left = parent.children[i - 1];
      if (left.keys.length > MIN_KEYS) {
        const pivot = parent.keys[i - 1];
        parent.keys[i - 1] = left.keys.pop()!;
        child.keys.unshift(pivot);
        return true;
      }
