export function csvToJson(csv: string): Row[] {
  if (!csv.trim()) return [];
  const parsed = parseCsv(csv);
  if (parsed.length === 0) return [];
  const headers = parsed[0];
  const result: Row[] = [];
  for (let i = 1; i < parsed.length; i++) {
    const row = parsed[i];
    if (row.length !== headers.length) {
