import axios, { AxiosResponse } from 'axios';

interface ConfigureOptions {
  baseURL: string;
  headers?: Record<string, string>;
}

let baseURL = '';
const defaultHeaders: Record<string, string> = {};

export function configure(options: ConfigureOptions): void {
  baseURL = options.baseURL;
  if (options.headers) {
    Object.assign(defaultHeaders, options.headers);
  }
}

export async function get<T = unknown>(path: string, params?: Record<string, unknown>): Promise<T> {
  const response: AxiosResponse<T> = await axios.get(baseURL + path, {
    params,
    headers: defaultHeaders,
  });
  return response.data;
}

export async function post<T = unknown>(path: string, body?: unknown, options?: { headers?: Record<string, string> }): Promise<T> {
  const response: AxiosResponse<T> = await axios.post(baseURL + path, body, {
    headers: {
      ...defaultHeaders,
      ...(options?.headers),
    },
  });
  return response.data;
}

export function buildQueryString(params: Record<string, unknown>): string {
  return Object.entries(params)
    .filter(([, v]) => v !== undefined && v !== null)
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`)
    .join('&');
}

interface RawResponseDataItem {
  id: string | number;
  name?: string;
  title?: string;
  meta?: Record<string, unknown>;
}

interface RawResponse {
  data?: {
    items?: RawResponseDataItem[];
  };
}

interface ParsedItem {
  id: string | number;
  label: string;
  meta: Record<string, unknown>;
}

function isRawResponse(value: unknown): value is RawResponse {
  if (typeof value !== 'object' || value === null) return false;
  const data = (value as RawResponse).data;
  if (typeof data !== 'object' || data === null) return false;
  return Array.isArray(data.items);
}

export function parseResponse(raw: unknown): ParsedItem[] {
  if (isRawResponse(raw) && raw.data?.items) {
    return raw.data.items.map(item => ({
      id: item.id,
      label: item.name || item.title || 'Unknown',
      meta: item.meta || {},
    }));
  }
  return [];
}

