export class EventBus {
  private _events: Record<string, Array<{ fn: Function; ctx: EventBus; once: boolean }>>;

  constructor() {
    this._events = {};
  }

  /**
   * Registers a listener for the specified event.
   * @param eventName - The name of the event to listen to.
   * @param callback - The function to call when the event is emitted.
   * @param context - The context (`this`) to use when calling the callback. Defaults to the EventBus instance.
   * @returns The EventBus instance for chaining.
   */
  on(eventName: string, callback: Function, context?: EventBus): this {
    const listeners = this._events[eventName] || (this._events[eventName] = []);
    listeners.push({ fn: callback, ctx: context || this, once: false });
    return this;
  }

  /**
   * Registers a one-time listener for the specified event.
   * @param eventName - The name of the event to listen to.
   * @param callback - The function to call when the event is emitted.
   * @param context - The context (`this`) to use when calling the callback. Defaults to the EventBus instance.
   * @returns The EventBus instance for chaining.
   */
  once(eventName: string, callback: Function, context?: EventBus): this {
    const self = this;
    const wrapper = function (...args: any[]) {
      self.off(eventName, wrapper);
      callback.apply(context || self, args);
    };
    (wrapper as any)._fn = callback;
    return this.on(eventName, wrapper, context);
  }

  /**
   * Emits the specified event, calling all registered listeners with the provided arguments.
   * @param eventName - The name of the event to emit.
   * @param args - Arguments to pass to the listeners.
   * @returns The EventBus instance for chaining.
   */
  emit(eventName: string, ...args: any[]): this {
    const listeners = this._events[eventName];
    if (!listeners) return this;

    const listenersCopy = listeners.slice();
    for (let i = 0; i < listenersCopy.length; i++) {
      listenersCopy[i].fn.apply(listenersCopy[i].ctx, args);
    }
    return this;
  }

  /**
   * Removes a listener for the specified event.
   * If no callback is provided, removes all listeners for that event.
   * @param eventName - The name of the event to remove listeners from.
   * @param callback - The specific callback function to remove. If omitted, all listeners for the event are removed.
   * @returns The EventBus instance for chaining.
   */
  off(eventName: string, callback?: Function): this {
    const listeners = this._events[eventName];
    if (!listeners) return this;

    if (!callback) {
      delete this._events[eventName];
      return this;
    }

    for (let i = listeners.length - 1; i >= 0; i--) {
      const listener = listeners[i];
      if (listener.fn !== callback && (listener.fn as any)._fn !== callback) {
        continue;
      }
      listeners.splice(i, 1);
      if (listeners.length === 0) {
        delete this._events[eventName];
      }
    }
    return this;
  }

  /**
   * Removes all registered events and listeners.
   * @returns The EventBus instance for chaining.
   */
  clear(): this {
    this._events = {};
    return this;
  }
}

