export function jaroWinkler(s1: string, s2: string): number {
    if (s1 === s2) return 1.0;
    if (s1.length === 0 || s2.length === 0) return 0.0;

    const len1 = s1.length;
    const len2 = s2.length;
    const window = Math.max(0, Math.floor(Math.max(len1, len2) / 2) - 1);

    const s1Matched = new Array(len1).fill(false);
    const s2Matched = new Array(len2).fill(false);
    let matches = 0;
    const s2Matches: number[] = [];

    for (let i = 0; i < len1; i++) {
        const start = Math.max(0, i - window);
        const end = Math.min(len2 - 1, i + window);
        for (let j = start; j <= end; j++) {
            if (s2Matched[j]) continue;
            if (s1[i] === s2[j]) {
                s1Matched[i] = true;
                s2Matched[j] = true;
                matches++;
                s2Matches.push(j);
                break;
            }
        }
    }

    if (matches === 0) return 0.0;

    let transpositions = 0;
    let k = 0;
    for (let i = 0; i < len1; i++) {
        if (s1Matched[i]) {
            if (s1[i] !== s2[s2Matches[k]]) {
                transpositions++;
            }
            k++;
        }
    }
    transpositions /= 2;

    const jaro = (matches / len1 + matches / len2 + (matches - transpositions) / matches) / 3;

    let prefixLength = 0;
    const maxPrefix = Math.min(4, Math.min(len1, len2));
    for (let i = 0; i < maxPrefix; i++) {
        if (s1[i] === s2[i]) {
            prefixLength++;
        } else {
            break;
        }
    }

    const p = 0.1;
    return jaro + (prefixLength * p * (1 - jaro));
}

