export type WrapOptions = {
	width?: number;
	lineBreak?: string;
	mode?: 'soft' | 'hard';
	hangingIndent?: string;
	collapseWhitespace?: boolean;
};

export function wordWrap(text: string, options?: WrapOptions): string {
	const {
		width = 80,
		lineBreak = '\n',
		mode = 'soft',
		hangingIndent = '',
		collapseWhitespace = false,
	} = options ?? {};

	const paragraphs = text.split('\n');

	return paragraphs.map(paragraph => {
		let content = paragraph;
		if (collapseWhitespace) {
			content = content.replace(/\s+/g, ' ').trim();
		}
		if (!content) return '';

		const lines: string[] = [];
		let currentLine = '';

		const words = content.split(' ');
		for (const word of words) {
			if (word.length === 0) continue;

			const space = currentLine ? ' ' : '';
			const needed = currentLine.length + space.length + word.length;

			if (needed <= width) {
				currentLine += space + word;
			} else {
				if (currentLine) {
					lines.push(currentLine);
					currentLine = '';
				}

				if (mode === 'hard' && word.length > width) {
					while (word.length > width) {
						lines.push(word.slice(0, width));
						word = word.slice(width);
					}
					currentLine = word;
				} else {
					currentLine = word;
				}
			}
		}
		if (currentLine) lines.push(currentLine);

		if (hangingIndent) {
			return lines.map((line, i) => (i === 0 ? line : hangingIndent + line)).join(lineBreak);
		}
		return lines.join(lineBreak);
	}).join('\n');
}
```
